class Employee {
    void work() {
        System.out.println("Employee is working");
    }
}

class Developer extends Employee {
    @Override
    void work() {
        System.out.println("Developer is writing code");
    }

    void debug() {
        System.out.println("Developer is debugging");
    }
}

public class Main {
    public static void main(String[] args) {
        // Upcasting (implicit)
        Employee emp = new Developer();
        emp.work();  // Overridden method runs
        // emp.debug();  // Compilation error

        // Downcasting (explicit)
        if (emp instanceof Developer) {
            Developer dev = (Developer) emp;
            dev.debug();  // Now accessible
            dev.work();
        }

        // Unsafe downcasting
        Employee emp2 = new Employee();
        System.out.println(emp2 instanceof Developer);  // false
        // Developer dev2 = (Developer) emp2;  // ClassCastException!
    }
}

class Shape {
    double area() {
        return 0;
    }

    String name() {
        return "Shape";
    }
}

class Circle extends Shape {
    double radius;
    Circle(double radius) { this.radius = radius; }

    @Override
    double area() { return Math.PI * radius * radius; }

    @Override
    String name() { return "Circle"; }
}

class Rectangle extends Shape {
    double width, height;
    Rectangle(double width, double height) {
        this.width = width;
        this.height = height;
    }

    @Override
    double area() { return width * height; }

    @Override
    String name() { return "Rectangle"; }
}

class Triangle extends Shape {
    double base, height;
    Triangle(double base, double height) {
        this.base = base;
        this.height = height;
    }

    @Override
    double area() { return 0.5 * base * height; }

    @Override
    String name() { return "Triangle"; }
}

public class Main {
    public static void main(String[] args) {
        Shape[] shapes = {
            new Circle(5),
            new Rectangle(4, 6),
            new Triangle(3, 8)
        };

        double totalArea = 0;
        for (Shape s : shapes) {
            double a = s.area();
            System.out.printf("%s area: %.2f%n", s.name(), a);
            totalArea += a;
        }
        System.out.printf("Total area: %.2f%n", totalArea);
    }
}

